 */

// ── Session Types ─────────────────────────────────────────────────────────

export type SessionType = "arcan" | "claude-code" | "codex";
export type SessionStatus = "active" | "idle" | "completed" | "failed";

export interface SessionInfo {
  id: string;
  sessionType: SessionType;
  status: SessionStatus;
  name: string;
  workdir: string;
  model?: string;
  createdAt: string;
}

export interface SpawnConfig {
  name: string;
  workdir?: string;
  model?: string;
  sessionId?: string;
}

// ── Server → Daemon (commands) ────────────────────────────────────────────

export type ServerMessage =
  | { type: "spawn"; sessionType: SessionType; config: SpawnConfig }
  | { type: "input"; sessionId: string; data: string }
  | { type: "resize"; sessionId: string; cols: number; rows: number }
  | {
      type: "approve";
      sessionId: string;
      approvalId: string;
      approved: boolean;
    }
  | { type: "kill"; sessionId: string }
  | { type: "list_sessions" }
  | { type: "ping" };

// ── Daemon → Server (events) ──────────────────────────────────────────────

export type DaemonMessage =
  | { type: "output"; sessionId: string; data: string; seq: number }
  | { type: "session_created"; session: SessionInfo }
  | { type: "session_ended"; sessionId: string; reason: string }
  | {
      type: "approval_request";
      sessionId: string;
      approvalId: string;
      capability: string;
      context: string;
    }
  | { type: "session_list"; sessions: SessionInfo[] }
  | {
      type: "node_info";
      name: string;
      hostname: string;
      capabilities: string[];
    }
  | { type: "pong" }
  | { type: "error"; code: string; message: string };

