      </div>

      {/* Nodes */}
      <section>
        <h2 className="mb-3 text-lg font-medium">Relay Nodes</h2>
        {nodes.length === 0 ? (
          <div className="rounded-lg border border-dashed p-8 text-center">
            <p className="text-muted-foreground text-sm">
